const router=require('express').Router(),db=require('../database/db'),{authenticate}=require('../middleware/auth');
router.get('/',authenticate,async(req,res)=>{const{companyId}=req.query;const[r]=await db.query('SELECT * FROM cost_centres WHERE company_id=? ORDER BY id',[companyId]);res.json(r);});
router.post('/',authenticate,async(req,res)=>{const{companyId,name,parentCentreId,description}=req.body;const[r]=await db.query('INSERT INTO cost_centres(company_id,name,parent_centre_id,description)VALUES(?,?,?,?)',[companyId,name,parentCentreId||null,description]);const[rows]=await db.query('SELECT * FROM cost_centres WHERE id=?',[r.insertId]);res.json(rows[0]);});
router.put('/:id',authenticate,async(req,res)=>{const{name,parentCentreId,description}=req.body;await db.query('UPDATE cost_centres SET name=?,parent_centre_id=?,description=? WHERE id=?',[name,parentCentreId||null,description,req.params.id]);const[r]=await db.query('SELECT * FROM cost_centres WHERE id=?',[req.params.id]);res.json(r[0]);});
router.delete('/:id',authenticate,async(req,res)=>{await db.query('DELETE FROM cost_centres WHERE id=?',[req.params.id]);res.json({message:'Deleted'});});
router.get('/allocations',authenticate,async(req,res)=>{const{companyId,costCentreId}=req.query;let sql='SELECT ca.*,cc.name as centre_name,l.name as ledger_name FROM cost_allocations ca LEFT JOIN cost_centres cc ON ca.cost_centre_id=cc.id LEFT JOIN ledgers l ON ca.ledger_id=l.id WHERE ca.company_id=?';const p=[companyId];if(costCentreId){sql+=' AND ca.cost_centre_id=?';p.push(costCentreId);}sql+=' ORDER BY ca.date DESC';const[r]=await db.query(sql,p);res.json(r);});
router.post('/allocations',authenticate,async(req,res)=>{const{companyId,costCentreId,voucherId,ledgerId,amount,date,narration}=req.body;const[r]=await db.query('INSERT INTO cost_allocations(company_id,cost_centre_id,voucher_id,ledger_id,amount,date,narration)VALUES(?,?,?,?,?,?,?)',[companyId,costCentreId,voucherId,ledgerId,amount,date,narration]);const[rows]=await db.query('SELECT * FROM cost_allocations WHERE id=?',[r.insertId]);res.json(rows[0]);});
router.get('/summary/:companyId',authenticate,async(req,res)=>{const[centres]=await db.query('SELECT * FROM cost_centres WHERE company_id=?',[req.params.companyId]);const result=await Promise.all(centres.map(async c=>{const[[{total}]]=await db.query('SELECT COALESCE(SUM(amount),0) as total FROM cost_allocations WHERE cost_centre_id=?',[c.id]);return{centreId:c.id,centreName:c.name,totalAllocated:+total};}));res.json(result);});
module.exports=router;
